import math
class Solution:
    def maximumSum(self, nums):
        n = len(nums)
        best = 0
        for mask in range(1, 1 << n):
            idxs = [i + 1 for i in range(n) if (mask >> i) & 1]
            ok = True
            for a in range(len(idxs)):
                for b in range(a + 1, len(idxs)):
                    p = idxs[a] * idxs[b]
                    r = math.isqrt(p)
                    if r * r != p:
                        ok = False
                        break
                if not ok:
                    break
            if ok:
                s = sum(nums[i - 1] for i in idxs)
                if s > best:
                    best = s
        return best

