class Solution:
    def maximumSum(self, nums):
        n = len(nums)
        groups = {}
        for idx in range(1, n + 1):
            x = idx
            part = 1
            d = 2
            while d * d <= x:
                cnt = 0
                while x % d == 0:
                    x //= d
                    cnt += 1
                if cnt % 2 == 1:
                    part *= d
                d += 1
            if x > 1:
                part *= x
            groups[part] = groups.get(part, 0) + nums[idx - 1]
        return max(groups.values())

