var maximumSum = function(nums) {
    const n = nums.length;
    const groups = new Map();
    for (let idx = 1; idx <= n; idx++) {
        let x = idx;
        let part = 1;
        for (let d = 2; d * d <= x; d++) {
            let cnt = 0;
            while (x % d === 0) {
                x = Math.floor(x / d);
                cnt++;
            }
            if (cnt % 2 === 1) part *= d;
        }
        if (x > 1) part *= x;
        groups.set(part, (groups.get(part) || 0) + nums[idx - 1]);
    }
    return Math.max(...groups.values());
};
